# eval_service/graders.py
import re, anthropic

_judge = anthropic.Anthropic()


def grade_case(case: dict, output: str) -> float:
    grader = case.get("grader", "exact_match")

    if grader == "exact_match":
        return 1.0 if output.strip() == str(case["expected"]).strip() else 0.0

    elif grader == "exact_match_ci":
        return 1.0 if output.strip().lower() == str(case["expected"]).strip().lower() else 0.0

    elif grader == "exact_number":
        try:
            expected = float(re.sub(r"[^0-9.-]", "", str(case["expected"])))
            actual = float(re.sub(r"[^0-9.-]", "", output.strip()))
            return 1.0 if abs(expected - actual) < 0.001 else 0.0
        except ValueError:
            return 0.0

    elif grader == "contains_all":
        needles = case.get("expected_contains", [])
        return 1.0 if all(n.lower() in output.lower() for n in needles) else 0.0

    elif grader == "llm_judge":
        rubric = case.get("rubric", "Is the output correct and high quality?")
        resp = _judge.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=50,
            messages=[{"role": "user", "content":
                f"Rate the following output 0-10 based on this rubric:\n"
                f"Rubric: {rubric}\n\nInput: {case['input']}\n\nOutput: {output}\n\n"
                f"Respond with only a number 0-10."}],
        )
        try:
            score = float(resp.content[0].text.strip()) / 10.0
            return max(0.0, min(1.0, score))
        except ValueError:
            return 0.0

    return 0.0
